	require.NoError(t, os.MkdirAll(badDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(badDir, "result.json"), []byte("not json"), 0o644))

	rootCmd := NewCommandFactory(dir).NewRootCommand()
